-- Cleanup migration for development seed data introduced by 030_seed_dev_data_v2.
--
-- Why this exists:
-- - Migration 030 inserted demo fixtures to ease local frontend work.
-- - Migrations are executed in every environment, including production.
-- - This migration removes those fixed demo rows from persisted data.
--
-- Safety:
-- - Targets only fixed UUIDs reserved for seed v2 data.
-- - Includes dependent rows that can block user deletion (non-cascade FKs).

-- Seed users (030)
-- f6000000-0000-0000-0000-000000000001..0004

-- 1) Break/clean non-cascade references to seeded users.
UPDATE plugin_changelogs
SET updated_by = NULL
WHERE updated_by IN (
    'f6000000-0000-0000-0000-000000000001',
    'f6000000-0000-0000-0000-000000000002',
    'f6000000-0000-0000-0000-000000000003',
    'f6000000-0000-0000-0000-000000000004'
);

DELETE FROM plugin_media
WHERE uploaded_by IN (
    'f6000000-0000-0000-0000-000000000001',
    'f6000000-0000-0000-0000-000000000002',
    'f6000000-0000-0000-0000-000000000003',
    'f6000000-0000-0000-0000-000000000004'
);

DELETE FROM audit_logs
WHERE actor_id IN (
    'f6000000-0000-0000-0000-000000000001',
    'f6000000-0000-0000-0000-000000000002',
    'f6000000-0000-0000-0000-000000000003',
    'f6000000-0000-0000-0000-000000000004'
);

-- 2) Remove binary rows tied to seeded versions.
DELETE FROM binaries
WHERE id IN (
    '09000000-0000-0000-0000-000000000001',
    '09000000-0000-0000-0000-000000000002',
    '09000000-0000-0000-0000-000000000003',
    '09000000-0000-0000-0000-000000000004',
    '09000000-0000-0000-0000-000000000005'
);

-- 3) Remove plugin dependency rows linked to seeded plugins/versions.
DELETE FROM plugin_dependencies
WHERE version_id IN (
        '08000000-0000-0000-0000-000000000001',
        '08000000-0000-0000-0000-000000000002',
        '08000000-0000-0000-0000-000000000003',
        '08000000-0000-0000-0000-000000000004',
        '08000000-0000-0000-0000-000000000005',
        '08000000-0000-0000-0000-000000000006',
        '08000000-0000-0000-0000-000000000007',
        '08000000-0000-0000-0000-000000000008'
    )
   OR dependency_plugin_id IN (
        '07000000-0000-0000-0000-000000000001',
        '07000000-0000-0000-0000-000000000002',
        '07000000-0000-0000-0000-000000000003',
        '07000000-0000-0000-0000-000000000004',
        '07000000-0000-0000-0000-000000000005',
        '07000000-0000-0000-0000-000000000006'
    );

-- 4) Remove seeded versions and plugin-category links.
DELETE FROM versions
WHERE id IN (
        '08000000-0000-0000-0000-000000000001',
        '08000000-0000-0000-0000-000000000002',
        '08000000-0000-0000-0000-000000000003',
        '08000000-0000-0000-0000-000000000004',
        '08000000-0000-0000-0000-000000000005',
        '08000000-0000-0000-0000-000000000006',
        '08000000-0000-0000-0000-000000000007',
        '08000000-0000-0000-0000-000000000008'
    )
   OR plugin_id IN (
        '07000000-0000-0000-0000-000000000001',
        '07000000-0000-0000-0000-000000000002',
        '07000000-0000-0000-0000-000000000003',
        '07000000-0000-0000-0000-000000000004',
        '07000000-0000-0000-0000-000000000005',
        '07000000-0000-0000-0000-000000000006'
    );

DELETE FROM plugin_categories
WHERE plugin_id IN (
    '07000000-0000-0000-0000-000000000001',
    '07000000-0000-0000-0000-000000000002',
    '07000000-0000-0000-0000-000000000003',
    '07000000-0000-0000-0000-000000000004',
    '07000000-0000-0000-0000-000000000005',
    '07000000-0000-0000-0000-000000000006'
);

-- 5) Remove seeded plugins.
DELETE FROM plugins
WHERE id IN (
    '07000000-0000-0000-0000-000000000001',
    '07000000-0000-0000-0000-000000000002',
    '07000000-0000-0000-0000-000000000003',
    '07000000-0000-0000-0000-000000000004',
    '07000000-0000-0000-0000-000000000005',
    '07000000-0000-0000-0000-000000000006'
);

-- 6) Remove seeded users.
DELETE FROM users
WHERE id IN (
    'f6000000-0000-0000-0000-000000000001',
    'f6000000-0000-0000-0000-000000000002',
    'f6000000-0000-0000-0000-000000000003',
    'f6000000-0000-0000-0000-000000000004'
);